#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,C; scanf("%d %d %d", &A, &B, &C);
        if(A+B+C==180) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

